import React from 'react';
import styled from 'styled-components';

const Container = styled.div`
  padding: 4rem 2rem;
  max-width: 1200px;
  margin: 0 auto;
  background-color: #f9fafb;
  min-height: 100vh;
`;

const Hero = styled.div`
  text-align: center;
  margin-bottom: 4.5rem;
`;

const HeroTitle = styled.h1`
  font-size: 3rem;
  color: #1a202c;
  font-weight: 700;
  margin-bottom: 1rem;
`;

const HeroSubtitle = styled.h2`
  font-size: 1.35rem;
  color: #475569;
  font-weight: 500;
  max-width: 720px;
  margin: 0 auto;
`;

const Section = styled.section`
  margin-bottom: 4.5rem;
`;

const SectionTitle = styled.h3`
  font-size: 2.1rem;
  color: #1e2937;
  margin-bottom: 1.8rem;
  font-weight: 700;
  position: relative;
  display: inline-block;

  &:after {
    content: '';
    position: absolute;
    bottom: -6px;
    left: 0;
    width: 60px;
    height: 3px;
    background: #667eea;
    border-radius: 2px;
  }
`;

const BioText = styled.p`
  font-size: 1.1rem;
  color: #475569;
  line-height: 1.85;
  margin-bottom: 1.6rem;
  max-width: 780px;
`;

const SkillsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));
  gap: 2.2rem;
`;

const SkillCategory = styled.div`
  background: #ffffff;
  padding: 2rem;
  border-radius: 12px;
  box-shadow: 0 4px 15px rgba(0, 0, 0, 0.05);
  border: 1px solid #f1f5f9;
`;

const SkillTitle = styled.h4`
  font-size: 1.35rem;
  color: #1e2937;
  margin-bottom: 1.2rem;
  font-weight: 700;
`;

const SkillList = styled.ul`
  list-style: none;
  padding: 0;
  margin: 0;
`;

const SkillItem = styled.li`
  font-size: 1.05rem;
  color: #334155;
  margin-bottom: 0.75rem;
  padding-left: 1.6rem;
  position: relative;
  line-height: 1.6;

  &:before {
    content: '→';
    color: #667eea;
    position: absolute;
    left: 0;
    font-weight: bold;
  }
`;

const About = () => (
  <Container>
    <Hero>
      <HeroTitle>About Joël Tiogo</HeroTitle>
      <HeroSubtitle>
        Business Development Manager &amp; Strategic Leader in Technology, Circularity &amp; Sustainable Growth
      </HeroSubtitle>
    </Hero>

    <Section>
      <SectionTitle>Professional Background</SectionTitle>
      <BioText>
        I am a growth-oriented Business Development Manager with an entrepreneurial mindset and an MBA in Technology and Sustainability from Frankfurt School of Finance &amp; Management.
      </BioText>
      <BioText>
        Currently, I drive commercial success for innovative Battery Passport solutions at AVL, helping organizations navigate the transition toward greater transparency, compliance, and circularity in the battery value chain.
      </BioText>
      <BioText>
        With experience as a former founder and CEO, I specialize in identifying new market opportunities, building strategic partnerships, and translating emerging technologies into tangible business growth — particularly at the intersection of sustainability, digital innovation, and ESG principles.
        Trilingual in French, English, and German, I bring international perspective from working across Europe, Africa, and North America.
      </BioText>
    </Section>

    <Section>
      <SectionTitle>Core Expertise</SectionTitle>
      <SkillsGrid>
        <SkillCategory>
          <SkillTitle>Business Development &amp; Market Growth</SkillTitle>
          <SkillList>
            <SkillItem>Go-to-Market Strategy &amp; Execution</SkillItem>
            <SkillItem>Partnership Development &amp; Negotiation</SkillItem>
            <SkillItem>Market Analysis &amp; Opportunity Identification</SkillItem>
            <SkillItem>Stakeholder &amp; Client Relationship Management</SkillItem>
            <SkillItem>Commercial Strategy &amp; Roadmap Development</SkillItem>
          </SkillList>
        </SkillCategory>

        <SkillCategory>
          <SkillTitle>Technology &amp; Digital Innovation</SkillTitle>
          <SkillList>
            <SkillItem>Digital Transformation Leadership</SkillItem>
            <SkillItem>Technology Adoption &amp; Integration</SkillItem>
            <SkillItem>Innovative Solution Positioning</SkillItem>
            <SkillItem>AI &amp; Emerging Tech Applications for Business</SkillItem>
          </SkillList>
        </SkillCategory>

        <SkillCategory>
          <SkillTitle>ESG, Circularity &amp; Sustainability</SkillTitle>
          <SkillList>
            <SkillItem>ESG Strategy &amp; Implementation</SkillItem>
            <SkillItem>Circular Economy Initiatives</SkillItem>
            <SkillItem>Sustainability &amp; Regulatory Compliance</SkillItem>
            <SkillItem>Sustainable Business Model Development</SkillItem>
          </SkillList>
        </SkillCategory>
      </SkillsGrid>
    </Section>
  </Container>
);

export default About;
